import { PalantirApiError } from "@osdk/shared.net.errors";
import { createFetchHeaderMutator, createFetchOrThrow, createRetryingFetch } from "@osdk/shared.net.fetch";

// eslint-disable-next-line @typescript-eslint/consistent-type-imports

export const USER_AGENT_HEADER = "Fetch-User-Agent";
export function createSharedClientContext(baseUrl, tokenProvider, userAgent, fetchFn = fetch, customHeaders) {
  if (baseUrl.length === 0) {
    throw new Error("baseUrl cannot be empty");
  }
  const parsedBaseUrl = new URL(baseUrl);
  if (!parsedBaseUrl.pathname.endsWith("/")) {
    parsedBaseUrl.pathname += "/";
  }
  const normalizedBaseUrl = parsedBaseUrl.toString();
  const retryingFetchWithAuthOrThrow = createFetchHeaderMutator(createRetryingFetch(createFetchOrThrow(fetchFn)), async headers => {
    if (customHeaders != null) {
      for (const [key, value] of Object.entries(customHeaders)) {
        if (key.toLowerCase() !== USER_AGENT_HEADER.toLowerCase()) {
          headers.set(key, value);
        }
      }
    }
    const token = await tokenProvider();
    headers.set("Authorization", `Bearer ${token}`);
    const customUserAgent = customHeaders ? Object.entries(customHeaders).find(([k]) => k.toLowerCase() === USER_AGENT_HEADER.toLowerCase())?.[1] : undefined;
    headers.set(USER_AGENT_HEADER, [headers.get(USER_AGENT_HEADER), userAgent, customUserAgent].filter(x => x && x?.length > 0).join(" "));
    return headers;
  });

  // because this is async await it preserves stack traces, which the retrying fetch does not
  const fetchWrapper = async (input, init) => {
    try {
      return await retryingFetchWithAuthOrThrow(input, init);
    } catch (error) {
      const betterError = error instanceof PalantirApiError ? new PalantirApiError(error.message, error.errorName, error.errorCode, error.errorDescription, error.statusCode, error.errorInstanceId, error.parameters) : new Error(`Captured stack trace for error: ${error.message ?? error}`);
      betterError.cause = error;
      throw betterError;
    }
  };
  return {
    baseUrl: normalizedBaseUrl,
    fetch: fetchWrapper,
    tokenProvider
  };
}